  ('aboriginal-f0899a01-moex-00310', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依行政罰法規定，下列敘述何者正確？', '["不得因不知法規而免除行政處罰責任，且按其情節只能減輕，不能免除處罰", "違反行政法上義務之行為非出於故意或過失者，不予處罰", "未滿16歲人之行為，不予處罰", "14歲以上，未滿18歲人之行為，得減輕或不罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00311', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依行政罰法之規定，甲為乙之利益而實施行為，致使乙違反行政法上義務應受處罰者，甲因其行為受 有財產上利益而未受處罰時，則行政機關得如何處理？', '["於甲所受財產上利益價值範圍內，酌予追徵", "於甲所受財產上利益價值範圍內，酌予追繳", "於甲所受財產上利益價值範圍內，全額追徵", "於甲所受財產上利益價值範圍內，全額追繳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00312', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於主管機關於行政罰裁處程序中所為之扣留，下列敘述何者錯誤？', '["對於可為證據之物，因有檢驗之必要，得予以扣留", "就有保全證據必要之物，要求持有人交付，持有人無正當理由拒絕時，行政機關僅能報請檢察官扣押", "扣留物之保管人在場時，執行人員應製作收據", "扣留之鞭炮有爆炸之危險時，得予以毀棄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
